#include "seven_seg_max7219.h"
#include <LedControl.h>
static LedControl lc(23,18,5,1);
void seg7_setup(){lc.shutdown(0,false);lc.setIntensity(0,4);lc.clearDisplay(0);Serial.println("[seg7] OK 8 digits");}
void seg7_show_number(long n){lc.clearDisplay(0);bool neg=n<0;if(neg)n=-n;for(int i=0;i<8&&(n>0||i==0);i++){lc.setDigit(0,i,n%10,false);n/=10;}}
void seg7_show_float(float n,uint8_t d){long mul=1;for(uint8_t i=0;i<d;i++)mul*=10;long val=(long)(n*mul);lc.clearDisplay(0);bool neg=val<0;if(neg)val=-val;for(int i=0;i<8&&(val>0||i==0);i++){lc.setDigit(0,i,val%10,i==d);val/=10;}}
void seg7_clear(){lc.clearDisplay(0);}
void seg7_set_brightness(uint8_t b){lc.setIntensity(0,constrain(b,0,15));}
